class Solution:
    def maximumRows(self, matrix, numSelect):
        from itertools import combinations
        m = len(matrix)
        n = len(matrix[0])
        best = 0
        for cols in combinations(range(n), numSelect):
            sel = set(cols)
            covered = 0
            for row in matrix:
                ok = True
                for j in range(n):
                    if row[j] == 1 and j not in sel:
                        ok = False
                        break
                if ok:
                    covered += 1
            best = max(best, covered)
        return best

