class Solution:
    def maximumRows(self, matrix, numSelect):
        n = len(matrix[0])
        row_masks = []
        for row in matrix:
            mask = 0
            for j in range(n):
                if row[j] == 1:
                    mask |= (1 << j)
            row_masks.append(mask)
        best = 0
        for subset in range(1 << n):
            if bin(subset).count('1') != numSelect:
                continue
            covered = sum(1 for rm in row_masks if (rm & subset) == rm)
            if covered > best:
                best = covered
        return best

