var maximumRows = function(matrix, numSelect) {
    const n = matrix[0].length;
    const rowMasks = [];
    for (const row of matrix) {
        let mask = 0;
        for (let j = 0; j < n; j++) if (row[j] === 1) mask |= (1 << j);
        rowMasks.push(mask);
    }
    let best = 0;
    for (let subset = 0; subset < (1 << n); subset++) {
        let bits = 0;
        for (let x = subset; x > 0; x >>= 1) bits += x & 1;
        if (bits !== numSelect) continue;
        let covered = 0;
        for (const rm of rowMasks) if ((rm & subset) === rm) covered++;
        if (covered > best) best = covered;
    }
    return best;
};
